def minRemoveToMakeValid(s):
    res, stack = list(s), []
    for i, c in enumerate(s):
        if c == "(": stack.append(i)
        elif c == ")":
            if stack: stack.pop()
            else: res[i] = ""
    while stack: res[stack.pop()] = ""
    return "".join(res)

